  CONSTRAINT `batch_attendance_ibfk_2` FOREIGN KEY (`schedule_id`) REFERENCES `batch_schedule` (`schedule_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
